mapper.select:
SELECT ,
       e.emp_name, e.emp_no, d.dept_name,
       a.emp_name as approver_name
FROM sys_leave l
LEFT JOIN sys_emp e ON l.emp_id = e.id
LEFT JOIN sys_dept d ON e.dept_id = d.id
LEFT JOIN sys_emp a ON l.approver_id = a.id


        AND l.emp_id = #{empId}


        AND e.emp_name LIKE CONCAT('%', #{empName}, '%')


        AND l.leave_type = #{leaveType}


        AND l.status = #{status}


         AND l.start_date >= #{startDateQuery} 


         AND l.end_date <= #{endDateQuery} 


ORDER BY l.create_time DESC

mapper.update:
UPDATE sys_leave
leave_type = #{leaveType}, start_date = #{startDate}, end_date = #{endDate}, leave_days = #{leaveDays}, reason = #{reason}, status = #{status},
WHERE id = #{id}

UPDATE sys_leave
SET status = #{status},
    approver_id = #{approverId},
    approve_time = NOW(),
    approve_remark = #{remark}
WHERE id = #{id}
